149→export function createInitialEditorState(activeFloorId) {
150→  const modelViewport = getInitialModelViewport();
151→  const sheetViewport = getInitialSheetViewport();
152→  return {
153→    activeTool: TOOLS.SELECT,
154→    selectedId: null,
155→    selectedType: null,
156→    toolState: {},
157→    workspaceMode: 'model',
158→    viewport: { ...modelViewport },
159→    modelViewport,
160→    sheetViewport,
161→    showGrid: true,
162→    snapEnabled: true,
163→    viewMode: 'plan',
164→    activeFloorId,
165→    activeSheetId: null,
166→    statusMessage: null,
167→  };
168→}
169→
170→export function EditorProvider({ children, activeFloorId }) {
171→  const [state, dispatch] = useReducer(
172→    editorReducer,
173→    activeFloorId,
174→    createInitialEditorState
175→  );
176→
177→  useEffect(() => {
178→    if (activeFloorId && activeFloorId !== state.activeFloorId) {
179→      dispatch({ type: 'SET_ACTIVE_FLOOR', floorId: activeFloorId });
180→    }
181→  }, [activeFloorId]);
182→
183→  return (
184→    <EditorContext.Provider value={{ state, dispatch }}>
185→      {children}
186→    </EditorContext.Provider>
187→  );
188→}
189→
190→export function useEditor() {
191→  const ctx = useContext(EditorContext);
192→  if (!ctx) throw new Error('useEditor must be used within EditorProvider');
193→  return { ...ctx.state, dispatch: ctx.dispatch };
194→}
